import React, { useState } from 'react';
import { Select, DateRangeFilter, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { sxService } from '../../../services/sx/sxService';
import type { ProductionOrderDto } from '../../../services/sx/models';
import { formatDateLocal, formatNumber, formatPercent } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const STATUS_OPTIONS = [
  { value: '', label: 'Tất cả' },
  { value: 'Released', label: 'Đang SX' },
  { value: 'Completed', label: 'Hoàn thành' },
  { value: 'Closed', label: 'Đóng' },
];

function orderStatusLabel(o: ProductionOrderDto): { label: string; tag: string } {
  const rate = formatPercent(o.completedQty, o.orderQty);
  const end = o.plannedEndDate ? new Date(o.plannedEndDate) : null;
  const late = end && end < new Date() && o.status !== 'Completed' && o.status !== 'Closed';
  if (o.status === 'Completed' || o.status === 'Closed') return { label: 'Hoàn thành', tag: styles.tagSuccess };
  if (late) return { label: 'Trễ hạn', tag: styles.tagError };
  return { label: 'Đang SX', tag: styles.tagWarning };
}

const BaoCaoThanhPhamDonHangPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const now = new Date();
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0, 10);
  const monthEnd = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().slice(0, 10);

  const [fromDate, setFromDate] = useState(monthStart);
  const [toDate, setToDate] = useState(monthEnd);
  const [status, setStatus] = useState('');
  const [rows, setRows] = useState<ProductionOrderDto[]>([]);
  const [loading, setLoading] = useState(false);
  const handleSearch = () => setReloadKey(k => k + 1);
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      sxService
        .getProductionOrders({
          status: status || undefined,
          fromDate,
          toDate,
          page: 1,
          pageSize: 200,
        })
        .then(res => { if (!cancelled) setRows(res.items); })
        .catch(err => {
          if (!cancelled)
            dispatch(addToast({ message: err?.message ?? 'Lỗi tải báo cáo', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [fromDate, toDate, status, dispatch, reloadKey]);

  const done = rows.filter(r => r.status === 'Completed' || r.status === 'Closed').length;
  const late = rows.filter(r => orderStatusLabel(r).label === 'Trễ hạn').length;
  const avgRate = rows.length
    ? Math.round(rows.reduce((a, r) => a + formatPercent(r.completedQty, r.orderQty), 0) / rows.length)
    : 0;

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-clipboard-list" /> BC thành phẩm theo đơn hàng</h1>
        </div>
      </div>

      <div className={styles.filtersBar} data-testid={`erp-bao-cao-thanh-pham-don-hang-filters`}>
        <DateRangeFilter
          fromDate={fromDate}
          toDate={toDate}
          onChange={(v: DateRangeValue) => { setFromDate(v.fromDate ?? ''); setToDate(v.toDate ?? ''); }}
        />
        <Select value={status} onChange={e => setStatus(e.target.value)} options={STATUS_OPTIONS} size="small" />
      </div>

      <div className={styles.summaryBar}>
        <div className={styles.summaryItem}><label className={styles.label}>Tổng LSX</label><strong>{rows.length}</strong></div>
        <div className={styles.summaryItem}><label className={styles.label}>Hoàn thành</label><strong>{done}</strong></div>
        <div className={styles.summaryItem}><label className={styles.label}>Trễ hạn</label><strong>{late}</strong></div>
        <div className={styles.summaryItem}><label className={styles.label}>Tiến độ TB</label><strong>{avgRate}%</strong></div>
        <ListSearchRefreshButtons testIdPrefix="erp-bao-cao-thanh-pham-don-hang" onSearch={handleSearch} onRefresh={refresh} showSearch={false} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : rows.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có đơn trong kỳ</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Số LSX</th>
                  <th>HĐ</th>
                  <th>Sản phẩm</th>
                  <th className={styles.colRight}>SL đặt</th>
                  <th className={styles.colRight}>SL HT</th>
                  <th>Tiến độ</th>
                  <th>Hạn</th>
                  <th>Trạng thái</th>
                </tr>
              </thead>
              <tbody>
                {rows.map(r => {
                  const pct = formatPercent(r.completedQty, r.orderQty);
                  const st = orderStatusLabel(r);
                  return (
                    <tr key={r.id} className={st.label === 'Trễ hạn' ? styles.rowDanger : undefined}>
                      <td><code>{r.code}</code></td>
                      <td>{r.contractCode ?? '—'}</td>
                      <td>{r.productName ?? r.productCode}</td>
                      <td className={styles.colRight}>{formatNumber(r.orderQty)}</td>
                      <td className={styles.colRight}>{formatNumber(r.completedQty)}</td>
                      <td>
                        <div className={styles.progressBar}>
                          <div className={styles.progressFill} style={{ width: `${Math.min(pct, 100)}%` }} />
                        </div>
                        <div className={styles.progressLabel}>{pct}%</div>
                      </td>
                      <td>{formatDateLocal(r.plannedEndDate)}</td>
                      <td><span className={st.tag}>{st.label}</span></td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default BaoCaoThanhPhamDonHangPage;
